export const API_BASE = process.env.NEXT_PUBLIC_API_URL ?? "http://localhost:8787";
export const SITE_BASE = process.env.NEXT_PUBLIC_SITE_URL ?? "http://localhost:3000";

export function buildOgImageUrl(
  type: "paper" | "org" | "collection",
  title: string,
  subtitle?: string,
): string {
  const url = new URL(`${SITE_BASE}/api/og`);
  url.searchParams.set("type", type);
  url.searchParams.set("title", title);
  if (subtitle) {
    url.searchParams.set("subtitle", subtitle);
  }
  return url.toString();
}
